//! # Saturation Metadata — Precomputed frozen-neuron bitmasks in .rknot
//!
//! This module extends the `.rknot` format to embed saturation profiling results
//! (frozen/redundant neuron bitmasks) from the profiling phase, enabling O(1)
//! lookup at inference time without recomputation.
//!
//! ## Motivation
//!
//! The saturation profiler detects frozen neurons (low variance) and redundant
//! activations per FFN layer. Previously, this detection happened at inference
//! time. Now we embed the bitmasks in KnotMetadata so inference kernels can:
//!
//! 1. Load precomputed bitmasks from disk (.rknot)
//! 2. O(1) lookup: `is_ffn_neuron_frozen(layer_id, neuron_id)` → read bit
//! 3. Skip computation for frozen neurons (sparse FFN kernel)
//! 4. Estimate speedup without per-run profiling
//!
//! ## File format
//!
//! The bitmasks are stored in KnotMetadata as optional SaturationMaps, serialized
//! as part of the JSON header. Each layer gets a bincode-serialized BitVec for
//! space efficiency (~1KB per layer for 8192 neurons).
//!
//! ## Integration points
//!
//! 1. **Encoding phase** — Pass SaturationMaps from profiler output to
//!    KnotEncoderConfig, which includes them in RknotHeader during .knot → .rknot
//! 2. **Loader phase** — When loading .rknot, RknotHeader carries saturation_maps
//! 3. **Inference phase** — Phi3Pipeline and other kernels call accessor methods
//!    to check frozen status and conditionally skip FFN neurons
//!
//! ## Overhead
//!
//! - Per-layer storage: ~1KB (8192 neurons / 8 bits per byte)
//! - Per-layer metadata: 3 stats floats × 4 bytes = 12 bytes
//! - Total for 32-layer model: ~32 KB (negligible vs model weights)
//! - Access latency: 1 array lookup + 1 bit test (~10 nanoseconds)

use serde::{Deserialize, Serialize};
use std::collections::HashMap;

/// Frozen/redundant neuron bitmask for one FFN layer.
///
/// Stores which neurons in the FFN intermediate layer are "saturated"
/// (low variance, near-zero gradients, or low activation patterns).
/// Serialized as Vec<u8> for compact storage; can be wrapped in BitVec
/// for runtime bit manipulation.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct LayerFrozenBitmask {
    /// Layer index (0..num_layers)
    pub layer_id: u32,
    /// Frozen neuron bitmask, packed as bytes. Length = ceil(num_neurons / 8).
    /// Bit i is set if neuron i is frozen. Little-endian bit order within bytes.
    pub frozen_mask: Vec<u8>,
    /// Total number of neurons in this layer's FFN intermediate.
    pub num_neurons: u32,
}

impl LayerFrozenBitmask {
    /// Creates a new bitmask for a layer with `num_neurons` neurons (all unfrozen).
    pub fn new(layer_id: u32, num_neurons: u32) -> Self {
        let byte_count = num_neurons.div_ceil(8) as usize;
        Self {
            layer_id,
            frozen_mask: vec![0u8; byte_count],
            num_neurons,
        }
    }

    /// Marks neuron `neuron_id` as frozen (sets its bit).
    pub fn freeze_neuron(&mut self, neuron_id: u32) {
        if neuron_id >= self.num_neurons {
            return; // out of bounds, silently ignore
        }
        let byte_idx = (neuron_id / 8) as usize;
        let bit_idx = (neuron_id % 8) as u8;
        if byte_idx < self.frozen_mask.len() {
            self.frozen_mask[byte_idx] |= 1 << bit_idx;
        }
    }

    /// Marks neuron `neuron_id` as active (clears its bit).
    pub fn unfreeze_neuron(&mut self, neuron_id: u32) {
        if neuron_id >= self.num_neurons {
            return;
        }
        let byte_idx = (neuron_id / 8) as usize;
        let bit_idx = (neuron_id % 8) as u8;
        if byte_idx < self.frozen_mask.len() {
            self.frozen_mask[byte_idx] &= !(1 << bit_idx);
        }
    }

    /// Tests whether neuron `neuron_id` is frozen.
    pub fn is_frozen(&self, neuron_id: u32) -> bool {
        if neuron_id >= self.num_neurons {
            return false; // out of bounds → not frozen
        }
        let byte_idx = (neuron_id / 8) as usize;
        let bit_idx = (neuron_id % 8) as u8;
        byte_idx < self.frozen_mask.len() && (self.frozen_mask[byte_idx] & (1 << bit_idx)) != 0
    }

    /// Counts the number of frozen neurons.
    pub fn num_frozen(&self) -> u32 {
        self.frozen_mask.iter().map(|b| b.count_ones()).sum()
    }

    /// Percentage of neurons frozen in [0, 100].
    pub fn pct_frozen(&self) -> f32 {
        if self.num_neurons == 0 {
            0.0
        } else {
            (self.num_frozen() as f32 / self.num_neurons as f32) * 100.0
        }
    }

    /// Estimated speedup if we skip frozen neurons.
    /// Simple model: 1 / (1 - pct_frozen).
    /// E.g., 50% frozen → 2x speedup, 80% → 5x, 95% → 20x.
    pub fn estimated_speedup(&self) -> f32 {
        let pct = self.pct_frozen() / 100.0;
        if pct >= 0.95 {
            20.0 // cap at 20x
        } else if pct > 0.0 {
            1.0 / (1.0 - pct)
        } else {
            1.0
        }
    }

    /// Returns the byte size of the frozen_mask.
    pub fn byte_size(&self) -> usize {
        self.frozen_mask.len()
    }
}

/// Per-layer saturation statistics (metadata only, not used for sparse ops).
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct LayerSaturationStat {
    pub layer_id: u32,
    /// Percentage of FFN neurons marked as frozen
    pub pct_frozen_ffn: f32,
    /// Estimated speedup from skipping frozen neurons (1.0 = no speedup)
    pub estimated_speedup: f32,
    /// Optional: timestamp when profiling was done (ISO 8601)
    pub profile_timestamp: Option<String>,
    /// Optional: which probe corpus was used for profiling
    pub profile_probe: Option<String>,
}

/// Top-level saturation maps collection (one per model).
///
/// Embedded in RknotHeader as `saturation_maps: Option<SaturationMaps>`.
/// If present, inference kernels can use it for frozen-neuron skipping.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SaturationMaps {
    /// Per-layer bitmasks (layer_id → frozen neurons)
    pub ffn_frozen_per_layer: HashMap<u32, LayerFrozenBitmask>,
    /// Per-layer statistics (for reporting/diagnostics)
    pub stats: Vec<LayerSaturationStat>,
    /// ISO 8601 timestamp: when profiling was completed
    pub profile_date: String,
    /// Profiling method identifier ("variance+gradient" or similar)
    pub profile_method: String,
    /// Optional: model name this was profiled on (e.g., "phi3-mini-4k-instruct")
    pub model_name: Option<String>,
}

impl SaturationMaps {
    /// Creates an empty SaturationMaps for a model with `num_layers` layers.
    pub fn new(_num_layers: usize, profile_method: String) -> Self {
        Self {
            ffn_frozen_per_layer: HashMap::new(),
            stats: Vec::new(),
            profile_date: current_profile_date(),
            profile_method,
            model_name: None,
        }
    }

    /// Sets the profile timestamp to a specific value (for reproducibility).
    pub fn with_date(mut self, date: String) -> Self {
        self.profile_date = date;
        self
    }

    /// Sets the model name.
    pub fn with_model_name(mut self, name: String) -> Self {
        self.model_name = Some(name);
        self
    }

    /// Adds a layer's frozen bitmask.
    pub fn insert_layer_mask(mut self, mask: LayerFrozenBitmask) -> Self {
        self.ffn_frozen_per_layer.insert(mask.layer_id, mask);
        self
    }

    /// Adds layer statistics.
    pub fn add_stat(mut self, stat: LayerSaturationStat) -> Self {
        self.stats.push(stat);
        self
    }

    /// Total bytes used by all bitmasks.
    pub fn total_bitmask_bytes(&self) -> usize {
        self.ffn_frozen_per_layer
            .values()
            .map(|m| m.byte_size())
            .sum()
    }

    /// Checks if a neuron in layer `layer_id` is frozen.
    pub fn is_ffn_neuron_frozen(&self, layer_id: u32, neuron_id: u32) -> bool {
        self.ffn_frozen_per_layer
            .get(&layer_id)
            .map(|mask| mask.is_frozen(neuron_id))
            .unwrap_or(false)
    }

    /// Gets estimated speedup for a layer (1.0 if not found).
    pub fn ffn_speedup_estimate(&self, layer_id: u32) -> f32 {
        self.ffn_frozen_per_layer
            .get(&layer_id)
            .map(|mask| mask.estimated_speedup())
            .unwrap_or(1.0)
    }

    /// Gets the percentage of frozen FFN neurons for a layer (0.0 if not found).
    pub fn pct_frozen(&self, layer_id: u32) -> f32 {
        self.ffn_frozen_per_layer
            .get(&layer_id)
            .map(|mask| mask.pct_frozen())
            .unwrap_or(0.0)
    }

    /// Computes mean speedup across all layers.
    pub fn mean_speedup(&self) -> f32 {
        if self.ffn_frozen_per_layer.is_empty() {
            return 1.0;
        }
        let sum: f32 = self
            .ffn_frozen_per_layer
            .values()
            .map(|m| m.estimated_speedup())
            .sum();
        sum / self.ffn_frozen_per_layer.len() as f32
    }

    /// Returns a summary string for logging/debugging.
    pub fn summary(&self) -> String {
        let n = self.ffn_frozen_per_layer.len();
        let mean = self.mean_speedup();
        format!(
            "SaturationMaps({} layers, method={}, mean_speedup={:.2}x, total_mask_bytes={})",
            n,
            self.profile_method,
            mean,
            self.total_bitmask_bytes()
        )
    }
}

#[cfg(not(target_arch = "wasm32"))]
fn current_profile_date() -> String {
    chrono::Utc::now().to_rfc3339()
}

#[cfg(target_arch = "wasm32")]
fn current_profile_date() -> String {
    "wasm32-unknown-time".to_string()
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn layer_bitmask_basic() {
        let mut mask = LayerFrozenBitmask::new(0, 8192);
        assert_eq!(mask.num_neurons, 8192);
        assert_eq!(mask.num_frozen(), 0);
        assert!(!mask.is_frozen(0));

        mask.freeze_neuron(42);
        assert!(mask.is_frozen(42));
        assert_eq!(mask.num_frozen(), 1);

        mask.freeze_neuron(100);
        assert_eq!(mask.num_frozen(), 2);

        mask.unfreeze_neuron(42);
        assert!(!mask.is_frozen(42));
        assert_eq!(mask.num_frozen(), 1);
    }

    #[test]
    fn layer_bitmask_out_of_bounds() {
        let mut mask = LayerFrozenBitmask::new(0, 100);
        mask.freeze_neuron(200); // out of bounds
        assert!(!mask.is_frozen(200));
        assert_eq!(mask.num_frozen(), 0); // no error, just ignored
    }

    #[test]
    fn layer_bitmask_pct_frozen() {
        let mut mask = LayerFrozenBitmask::new(0, 100);
        for i in 0..50 {
            mask.freeze_neuron(i);
        }
        assert!((mask.pct_frozen() - 50.0).abs() < 0.01);
    }

    #[test]
    fn layer_bitmask_speedup() {
        let mut mask = LayerFrozenBitmask::new(0, 100);
        for i in 0..80 {
            mask.freeze_neuron(i);
        }
        let speedup = mask.estimated_speedup();
        assert!(speedup >= 4.5 && speedup <= 5.5); // ~5x for 80%
    }

    #[test]
    fn saturation_maps_basic() {
        let maps = SaturationMaps::new(32, "variance+gradient".to_string());
        assert_eq!(maps.ffn_frozen_per_layer.len(), 0);
        assert_eq!(maps.mean_speedup(), 1.0);

        let maps = maps
            .with_model_name("phi3-mini".to_string())
            .insert_layer_mask(LayerFrozenBitmask::new(0, 8192));
        assert_eq!(maps.ffn_frozen_per_layer.len(), 1);
    }

    #[test]
    fn saturation_maps_neuron_frozen_lookup() {
        let mut mask = LayerFrozenBitmask::new(5, 4096);
        mask.freeze_neuron(100);
        mask.freeze_neuron(200);

        let maps = SaturationMaps::new(32, "variance+gradient".to_string()).insert_layer_mask(mask);

        assert!(maps.is_ffn_neuron_frozen(5, 100));
        assert!(maps.is_ffn_neuron_frozen(5, 200));
        assert!(!maps.is_ffn_neuron_frozen(5, 101));
        assert!(!maps.is_ffn_neuron_frozen(6, 100)); // different layer
    }

    #[test]
    fn saturation_maps_speedup_estimate() {
        let mut mask = LayerFrozenBitmask::new(0, 1000);
        for i in 0..900 {
            mask.freeze_neuron(i);
        }
        let maps = SaturationMaps::new(32, "variance+gradient".to_string()).insert_layer_mask(mask);

        let speedup = maps.ffn_speedup_estimate(0);
        assert!(speedup >= 8.0 && speedup <= 12.0); // ~10x for 90%
    }

    #[test]
    fn saturation_maps_byte_size() {
        let mask1 = LayerFrozenBitmask::new(0, 8192); // 1024 bytes
        let mask2 = LayerFrozenBitmask::new(1, 4096); // 512 bytes
        let maps = SaturationMaps::new(32, "variance+gradient".to_string())
            .insert_layer_mask(mask1)
            .insert_layer_mask(mask2);

        assert_eq!(maps.total_bitmask_bytes(), 1024 + 512);
    }
}
